mapper.delete:
DELETE FROM user_follow
WHERE follower_id = #{followerId}
  AND followee_id = #{followeeId}

mapper.select:
SELECT COUNT(1) > 0
FROM user_follow
WHERE follower_id = #{followerId}
  AND followee_id = #{followeeId}

SELECT u.id AS userId, u.username, u.nickname, u.avatar, u.gender, f.created_at AS followedAt FROM user_follow f INNER JOIN `user` u ON u.id = f.follower_id AND u.deleted_at IS NULL AND u.status = 1 WHERE f.followee_id = #{followeeId}
AND ( f.created_at < #{cursorCreatedAt} OR (f.created_at = #{cursorCreatedAt} AND f.follower_id < #{cursorTieBreaker}) )
ORDER BY f.created_at DESC, f.follower_id DESC LIMIT #{limit}

